    RagicBundle bundle = (RagicBundle)session.getAttribute("RAGIC_BUNDLE");
    User user = (User)session.getAttribute("USER");
    String apname=request.getParameter("a");
    if(user==null) return;

    Log log = new Log("log/menuSave.log").setIfDisplayTime(true);
    MenuLog menuLog = new MenuLog(log, apname, user.getUserId());

    //群組管理員,但可控頁籤為0返回
    HashSet<String> groupUnionTabs = user.getGroupsUnionTabs(apname);
    if(!user.ifApManager(apname) && groupUnionTabs.size() ==0) return;

    int menuSetIndex=Encoder.parseInt(request.getParameter("msi"),-1);
    if(menuSetIndex==-1) return;

    String originOpenSaveEditTime = Encoder.isEmptyOrWhitespaceOnly(request.getParameter("menuSaveEditTime")) ?
     "": request.getParameter("menuSaveEditTime");

    HomeConfig homeConfig = Account.getInstance(apname).getHomeConfig();

    String format = "yyyyMMdd hh:mm:ss";
    SimpleDateFormat sdf = new SimpleDateFormat(format);

    String json=request.getParameter("c");
    if(json!=null){
    //如果同時編輯則擋住 ex 同帳號雙開
    if(homeConfig.isSameTimeEdit(originOpenSaveEditTime)){
        out.print(bundle.getString("sheetArrangeBlockMsg"));

        return;
    }else{
              SystemTaskProgress.setStatus(apname,
                Const.STP_RESORT_MENU,
                "Saving your new menu configuration...",
                1,
                SystemTaskProgress.Status.PROCESSING
        );

        JSONObject jo = new JSONObject(json);
        MenuConfiguration mc= Account.getInstance(apname).getMenuConfiguration();
        MenuSet ms=new MenuSet(jo,mc);

        //[BugId:13791]
        MenuSet currentMenuSet=mc.getMenuSet(menuSetIndex);
        ms.setBanner(currentMenuSet.getBanner());
        ms.setLogoIcon(currentMenuSet.getLogoIcon());
        ms.setDarkTheme(currentMenuSet.isDarkTheme());

        //builder模式set值, 因為有些值為必填,有些值為選填 故採用此模式
        MenuSheetManagerUpdateAction updateAction = MenuSheetManagerUpdateAction.getBuilder(menuLog, currentMenuSet.getName())
                .setOldConfig(currentMenuSet.getJSON())
                .setNewConfig(jo)
                .build();
        menuLog.genMenuSheetManagerLog(updateAction, updateAction.getConfigJsonInfo());

        int moveCount=0;

        homeConfig.updateMenuSaveEditTime(sdf.format(new Date())); //因為sheet.moveToPath(path user), 我們不用再call homeconfig.save

        //process change of path
        for(MenuTab tab:ms.listTabs(user, Const.NORIGHT,false,false)){
            if(tab==null) {
               menuLog.info("this tab is null so escape", true);
              continue;
            }
            for(MenuSheet sheet:tab.getSheets()){
                if(sheet==null){
                  menuLog.info("this sheet is null so escape, tabPath: " + tab.getPath(), true);
                    continue;
                }

                 String fromPath = sheet.getPath();
                 String toPath = tab.getPath();
                if(!toPath.equals(fromPath)){
                    sheet.moveToPath(toPath, user);

                //紀錄表單移動path
                MenuSheetManagerUpdateAction pathMoveAction =
                MenuSheetManagerUpdateAction.getBuilder(menuLog, currentMenuSet.getName())
                    .setSheetName(sheet.getName())
                    .setFromPath(fromPath)
                    .setToPath(toPath)
                    .build();
                menuLog.genMenuSheetManagerLog(pathMoveAction, pathMoveAction.getSheetMovePathJsonInfo());

                    SystemTaskProgress.setStatus(apname,
                            Const.STP_RESORT_MENU,
                            "Rearranging your sheets...",
                            ++moveCount,
                            SystemTaskProgress.Status.PROCESSING
                    );
                }
            }
        }

        mc.setMenuSet(menuSetIndex,ms);
        mc.save();

        // clear cache, notice resetAppCache will be done at rearrange process
        NUIFormSetInfo.resetForms(apname, session);

        SystemTaskProgress.setStatus(apname,
                Const.STP_RESORT_MENU,
                "Finished rearranging your sheets.",
                -1,
                SystemTaskProgress.Status.DONE
        );

        out.print("success");
   }

}



